async (params, browser) => {
  // Open Hacker News newest page
  await browser.open('https://news.ycombinator.com/newest')

  // Wait for stories to load
  await browser.waitForSelector('.athing', 15000)

  // Let page settle
  await browser.wait(1500)

  // Extract newest stories
  const newest_data = await browser.evaluate(`const stories = []; const storyRows = document.querySelectorAll('.athing'); for (let i = 0; i < Math.min(storyRows.length, 30); i++) { const row = storyRows[i]; const subtext = row.nextElementSibling; const rankEl = row.querySelector('.rank'); const titleEl = row.querySelector('.titleline > a'); const scoreEl = subtext ? subtext.querySelector('.score') : null; const authorEl = subtext ? subtext.querySelector('.hnuser') : null; const ageEl = subtext ? subtext.querySelector('.age a') : null; let commentCount = '0'; if (subtext) { const links = subtext.querySelectorAll('a'); for (const link of links) { const text = link.textContent.trim(); if (text.includes('comment')) { commentCount = text.split('\u00a0')[0] || text.split(' ')[0]; break; } } } stories.push({ rank: rankEl ? parseInt(rankEl.textContent.trim().replace('.', ''), 10) : i + 1, title: titleEl ? titleEl.textContent.trim() : '', url: titleEl ? titleEl.href : '', score: scoreEl ? scoreEl.textContent.trim() : '0 points', author: authorEl ? authorEl.textContent.trim() : '', comment_count: commentCount, age: ageEl ? ageEl.textContent.trim() : '' }); } return { source: 'Hacker News - Newest', story_count: stories.length, stories: stories }`)

  return newest_data
}
